#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    ret = texture( sampler_main, vUv ).xyz;

    // ERROR DIFFUSION DITHER - looks great
    vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw + rand_frame.xy;
    ret += (texture(sampler_noise_lq, dither_uv).xyz-0.5)/256.0*1;

    // mix in img...
    vec3 pic = texture(sampler_pic, vUvOriginal*uAspect.xy).xyz;
    float lum = lum(pic);
    float use_it = abs(lum*0.8+0.1 - (0.5+roam_cos.y*0.25));
    float LFNoise = texture(sampler_noise_lq, vUv*0.1 + uTime*0.01).x*6-2;
    use_it = clamp01(1 - use_it*(3+9*rand_preset.x) - LFNoise);
    ret = mix(ret, pic, use_it.xxx);

    // darken over uTime
    //ret -= 0.004;
    //ret *= 0.99;
    ret *= 0.97 + 0.03*clamp01( length(vUv - vUvOriginal)*200 );  // center only
vec4 noise2 = texture3D(sampler_noisevol_hq,
                      ((vUv.xyy
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*0.4
                     );
float br = ret.x+ret.y+ret.z;
if(br>.1 && br<=1.21)ret += (noise2)*.5;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vUv *= uAspect.xy;
vec2 uv1 = (vUv-.5);

vec2 hor = vec2 (uTexSize.z,audioLow*uTexSize.y);
vec2 ver = vec2 (audioHigh,audioMid*uTexSize.w);
float dx = lum(GetPixel (vUv-hor)) - lum(GetPixel (vUv+hor));
float dy = lum(GetPixel (vUv-ver)) - lum(GetPixel (vUv+ver));
vec2 dz = vec2 (20*dx,dy);

uv1 = .3*tan((vUv+.02*uTime)*6) + .3*dz;
vec3 dots = clamp01(.004*q26/length(uv1))*hue_shader;

vec3 clouds = (texture(sampler_rand00, vUvOriginal+dz));
clouds += lum(clouds)-.7;

vec3 ret1 = .1*texture(sampler_main, vUv) ;

ret = -2*ret1 + audioLow*dots  + .4*clouds;
vec4 noise2 = texture3D(sampler_noisevol_hq,
                      ((vUv.xyy
                       )*uTexSize.xyy*texsize_noisevol_hq.zww
                      ).xyz*
                      vec3(1,1,0)*0.05 +
                      uTime*vec3(0,0,1)*0.4
                     );
float br = ret.x+ret.y+ret.z;
if(br>.1 && br<=.21)ret += (noise2)*.5;
ret=.3-ret;

  fragColor = ret;
}
